        color: var(--bg-parchment);
        font-family: 'Cedarville Cursive', cursive;
        cursor: pointer;
      }

      /* Scrollbar Styling */
      .journal-entry::-webkit-scrollbar {
        width: 12px;
      }

      .journal-entry::-webkit-scrollbar-track {
        background: var(--text);
      }

      .journal-entry::-webkit-scrollbar-thumb {
        background-color: var(--secondary-color);
        border-radius: 10px;
        width: 8px;
      }

      /* Placeholder styling */
      .journal-title::placeholder,
      .journal-date::placeholder,
      .journal-entry::placeholder {
        color: var(--text);
        opacity: 1;
      }

      /* Responsive tweaks */
      @media (max-width: 768px) {
        .journal-heading {
          font-size: 2rem;
        }

        .journal-title,
        .journal-date {
          font-size: 1rem;
        }

        .journal-entry {
          font-size: 1rem;
        }

        .journal-analyze {
          font-size: 1.1rem;
          width: 100%;
          max-width: 200px;
        }
      }

      @media (max-width: 480px) {
        .journal-heading {
          font-size: 1.7rem;
        }

        .journal-title,
        .journal-date {
          width: 100%;
          font-size: 0.95rem;
        }

        .journal-entry {
          font-size: 0.95rem;
        }

        .journal-analyze {
          font-size: 1rem;
          padding: 10px;
        }
      }
    `}</style>
  );
};


export default Journal;


